#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

static float
d_dist(int p1, int p2, int num, int dim, const float *coord_d)
{
    float retval = 0.0f;
    for(int i = 0; i < dim; i++){
        float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
        retval = retval + (tmp * tmp);
    }
    return retval;
}

__kernel void
kernel_compute_cost(int num, int dim, long x, const Point_Struct *p, int K, int stride,
                    const float *coord_d, float *work_mem_d, const int *center_table_d, char *switch_membership_d)
{
    int bid = get_block_id(0);
    int bdim = get_num_blocks(0);

    // Handle 2D grid emulation if needed by the launcher
    // The CUDA code emulated 2D grid: bid = blockIdx.x + gridDim.x * blockIdx.y
    // In OpenCL, if launched with 2 dimensions, get_block_id(1) will be valid
    if (get_num_blocks(1) > 1) {
        int grid_dim_x = get_num_blocks(0);
        bid = get_block_id(0) + get_block_id(1) * grid_dim_x;
        bdim = grid_dim_x * get_num_blocks(1);
    }

    int tid = get_block_size(0) * bid + get_thread_id(0);

    if(num > tid)
    {
        float *lower = &work_mem_d[tid*stride];

        float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

        if ( p[tid].cost > x_cost )
        {
            switch_membership_d[tid] = 1;
            lower[K] += x_cost - p[tid].cost;
        }
        else
        {
            lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
        }
    }
}
